// Script to generate or update package-lock.json

const fs = require('fs');
const path = require('path');

function ensurePackageLock() {
  const packageJsonPath = path.join(__dirname, 'package.json');
  const lockFilePath = path.join(__dirname, 'package-lock.json');

  if (!fs.existsSync(packageJsonPath)) {
    console.error('Error: No package.json found in the current directory.');
    process.exit(1);
  }

  // Run npm install to generate or update package-lock.json
  const { exec } = require('child_process');
  exec('npm install', (error, stdout, stderr) => {
    if (error) {
      console.error(`Error: ${stderr}`);
      process.exit(1);
    }
    if (fs.existsSync(lockFilePath)) {
      console.log('package-lock.json generated/updated successfully.');
    } else {
      console.error('Failed to generate/update package-lock.json.');
      process.exit(1);
    }
  });
}

ensurePackageLock();